(16, 10, 'Joost', 'jlucker@gmail.com', '', '203.219.141.119', '2011-07-22 10:39:24', '2011-07-22 10:39:24', 'wow, you recently added a lot of new pics. They look great. There is one of the space centre in Seattle with the purple tubes, I guess inside the place, which I really like.', 0, '1', 'Mozilla/5.0 (Windows NT 6.1; WOW64; rv:5.0) Gecko/20100101 Firefox/5.0', 'comment', 0, 0),
(15, 10, 'Mikaella Tri L', 'mikaella-tri@hotmail.com', 'http://none', '175.138.159.218', '2011-07-12 08:37:13', '2011-07-12 08:37:13', 'love your work, specialy the photography part. \r\nmy favorite is 2005 Jeanne dárc in Paris. Upload more photos, no?', 0, '1', 'Mozilla/4.0 (compatible; MSIE 8.0; Windows NT 6.0; Trident/4.0; GTB7.1; SLCC1; .NET CLR 2.0.50727; .NET CLR 3.5.30729; .NET CLR 3.0.30729; .NET4.0C)', 'comment', 0, 0),
(12, 10, 'Gruyters Frans', 'gonny@telenet.be', '', '94.227.108.200', '2011-05-24 17:18:03', '2011-05-24 17:18:03', 'Producten die van/uit de handen van Peter komen zijn professioneel, en ook de site!\r\n\r\nGeweldig!', 0, '1', 'Mozilla/5.0 (Macintosh; U; Intel Mac OS X 10.5; nl; rv:1.9.2.15) Gecko/20110303 Firefox/3.6.15', 'comment', 0, 0),
(10, 10, 'joost', 'jlucker@gmail.com', '', '84.29.46.159', '2011-04-27 10:41:19', '2011-04-27 10:41:19', 'hallo, wat een mooie site!\r\nDus veel dank aan Johannes', 0, '1', 'Mozilla/5.0 (Windows NT 6.1; WOW64; rv:2.0) Gecko/20100101 Firefox/4.0', 'comment', 0, 0),
(13, 10, 'Margriet', 'email@mcloudt.nl', 'http://blog.mcloudt.nl', '80.112.234.204', '2011-06-30 05:40:21', '2011-06-30 05:40:21', 'Sjiek werk Peter, vooral het schilderij van dat dorp in Alaska: Ketchikan Creek Street, prachtig !!', 0, '1', 'Mozilla/4.0 (compatible; MSIE 7.0; Windows NT 5.1; .NET CLR 2.0.50727; .NET CLR 3.0.4506.2152; .NET CLR 3.5.30729; .NET4.0C)', 'comment', 0, 0),
(22, 10, 'Robert Davis', 'R_B_D_@hotmail.com', '', '174.6.0.255', '2012-02-29 06:14:25', '2012-02-29 06:14:25', 'Love your work. Love your landscapes and photos. Very inspirational. Am a friend of your son Joost. Peace!', 0, '1', 'Mozilla/5.0 (Macintosh; Intel Mac OS X 10_6_8) AppleWebKit/534.52.7 (KHTML, like Gecko) Version/5.1.2 Safari/534.52.7', 'comment', 0, 0),
(23, 10, 'Stefan', 's.woestenberg@planet.nl', '', '84.84.12.67', '2012-05-27 07:54:42', '2012-05-27 07:54:42', 'Hoi Peter, echt schitterende schilderijen, ze leven, zijn echt. Je voelt de warmte, kunt het water aanraken, je ruikt de frisse berglucht of geur van de zee. Je kijkt door de ogen naar de ziel van de geschilderde persoon.  Het perfectionisme, de liefde voor details. Bijzonder bewonderenswaardig, een genot om naar te kijken.', 0, '1', 'Mozilla/5.0 (compatible; MSIE 9.0; Windows NT 6.1; WOW64; Trident/5.0)', 'comment', 0, 0),
(57, 10, 'Huub Rossel', 'info@huubrossel.nl', 'http://www.huubrossel.nl', '86.91.242.16', '2013-05-19 18:58:09', '2013-05-19 18:58:09', 'Beste Peter ik heb vanavond je site bekeken en ik heb ALLES gezien!!\r\nIk WILDE alles ook zien.\r\nIn een woord geweldig!!\r\nBen zeer onder de indruk van jouw kunnen. Groet Huub Rossel\r\n\r\n', 0, '1', 'Mozilla/5.0 (Windows NT 6.1; WOW64) AppleWebKit/537.11 (KHTML, like Gecko) Chrome/23.0.1271.91 Safari/537.11', 'comment', 0, 0),
