/wp:heading -->";}i:4;O:8:"stdClass":7:{s:2:"id";i:669;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:31:"Image and quote on a background";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:2291:"\n<div class="wp-block-media-text alignwide has-media-on-the-right is-stacked-on-mobile is-vertically-aligned-center has-background" style="background-color:#f1f5c7"><figure class="wp-block-media-text__media"><img loading="lazy" width="1024" height="1024" src="https://s.w.org/patterns/files/2021/06/pear-1-1024x1024.png" alt="" class="wp-image-5263 size-full" srcset="https://s.w.org/patterns/files/2021/06/pear-1-1024x1024.png 1024w, https://s.w.org/patterns/files/2021/06/pear-1-300x300.png 300w, https://s.w.org/patterns/files/2021/06/pear-1-150x150.png 150w, https://s.w.org/patterns/files/2021/06/pear-1-768x768.png 768w, https://s.w.org/patterns/files/2021/06/pear-1.png 1300w" sizes="(max-width: 1024px) 100vw, 1024px" /></figure><div class="wp-block-media-text__content">\n<div class="wp-container-11 wp-block-group" style="padding-top:2em;padding-right:2em;padding-bottom:2em;padding-left:2em"><div class="wp-block-group__inner-container">\n<p style="font-size:36px;line-height:1.2"><strong>Even the bitterest fruit has sugar in it.</strong></p>\n\n\n\n<p class="has-extra-small-font-size">– Terry a O&#8217;Neal</p>\n</div></div>\n</div></div>\n\n\n\n<div class="wp-block-media-text alignwide is-stacked-on-mobile is-vertically-aligned-center has-background" style="background-color:#fffdea"><figure class="wp-block-media-text__media"><img loading="lazy" width="1024" height="1024" src="https://s.w.org/patterns/files/2021/06/pear-half-1024x1024.png" alt="" class="wp-image-673 size-full" srcset="https://s.w.org/patterns/files/2021/06/pear-half-1024x1024.png 1024w, https://s.w.org/patterns/files/2021/06/pear-half-300x300.png 300w, https://s.w.org/patterns/files/2021/06/pear-half-150x150.png 150w, https://s.w.org/patterns/files/2021/06/pear-half-768x768.png 768w, https://s.w.org/patterns/files/2021/06/pear-half.png 1300w" sizes="(max-width: 1024px) 100vw, 1024px" /></figure><div class="wp-block-media-text__content">\n<div class="wp-container-12 wp-block-group" style="padding-top:2em;padding-right:2em;padding-bottom:2em;padding-left:2em"><div class="wp-block-group__inner-container">\n<p style="font-size:36px;line-height:1.2"><strong>The trees that are slow to grow bear the best fruit.</strong></p>\n\n\n\n<p class="has-extra-small-font-size">– Molière</p>\n</div></div>\n</div></div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":7:{s:10:"spay_email";s:0:"";s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:221:"Two media and text blocks. The top one has a pale green background. The text is on the left and contains a quote, and the image is on the right. The next block underneath has the image on the left, and quote on the right.";s:19:"wpop_viewport_width";i:800;s:16:"wpop_block_types";a:0:{}s:11:"wpop_locale";s:5:"en_US";s:20:"wpop_unlisted_reason";s:0:"";}s:14:"category_slugs";a:3:{i:0;s:8:"featured";i:1;s:6:"images";i:2;s:4:"text";}s:13:"keyword_slugs";a:0:{}s:15:"pattern_content";s:2404:"<!-- wp:media-text {"mediaPosition":"right","mediaId":5263,"mediaLink":"https://wordpress.org/patterns/pattern/image-and-quote-on-a-background/pear-3/","mediaType":"image","verticalAlignment":"center","style":{"color":{"background":"#f1f5c7"}}} -->\n<div class="wp-block-media-text alignwide has-media-on-the-right is-stacked-on-mobile is-vertically-aligned-center has-background" style="background-color:#f1f5c7"><figure class="wp-block-media-text__media"><img src="https://s.w.org/patterns/files/2021/06/pear-1-1024x1024.png" alt="" class="wp-image-5263 size-full" /></figure><div class="wp-block-media-text__content"><!-- wp:group {"style":{"spacing":{"padding":{"top":"2em","right":"2em","bottom":"2em","left":"2em"}}}} -->\n<div class="wp-block-group" style="padding-top:2em;padding-right:2em;padding-bottom:2em;padding-left:2em"><!-- wp:paragraph {"style":{"typography":{"lineHeight":"1.2","fontSize":"36px"}}} -->\n<p style="font-size:36px;line-height:1.2"><strong>Even the bitterest fruit has sugar in it.</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"fontSize":"extra-small"} -->\n<p class="has-extra-small-font-size">– Terry a O''Neal</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div></div>\n<!-- /wp:media-text -->\n\n<!-- wp:media-text {"mediaId":673,"mediaLink":"https://wordpress.org/patterns/pear-half/","mediaType":"image","verticalAlignment":"center","style":{"color":{"background":"#fffdea"}}} -->\n<div class="wp-block-media-text alignwide is-stacked-on-mobile is-vertically-aligned-center has-background" style="background-color:#fffdea"><figure class="wp-block-media-text__media"><img src="https://s.w.org/patterns/files/2021/06/pear-half-1024x1024.png" alt="" class="wp-image-673 size-full" /></figure><div class="wp-block-media-text__content"><!-- wp:group {"style":{"spacing":{"padding":{"top":"2em","right":"2em","bottom":"2em","left":"2em"}}}} -->\n<div class="wp-block-group" style="padding-top:2em;padding-right:2em;padding-bottom:2em;padding-left:2em"><!-- wp:paragraph {"style":{"typography":{"lineHeight":"1.2","fontSize":"36px"}}} -->\n<p style="font-size:36px;line-height:1.2"><strong>The trees that are slow to grow bear the best fruit.</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"fontSize":"extra-small"} -->\n<p class="has-extra-small-font-size">– Molière</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div></div>\n<!-- /wp:media-text -->";}i:5;O:8:"stdClass":7:{s:2:"id";i:573;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:37:"Image on solid color with description";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:1536:"\n<div class="wp-container-14 wp-block-columns alignfull">\n<div class="wp-block-column" style="flex-basis:50%">\n<div class="wp-block-cover has-background-dim" style="background-color:#f6f6f6;min-height:600px"><div class="wp-block-cover__inner-container">\n<div class="wp-block-image"><figure class="aligncenter size-medium"><img loading="lazy" width="263" height="300" src="https://s.w.org/patterns/files/2021/06/wire-sculpture-263x300.jpg" alt="" class="wp-image-571" srcset="https://s.w.org/patterns/files/2021/06/wire-sculpture-263x300.jpg 263w, https://s.w.org/patterns/files/2021/06/wire-sculpture-898x1024.jpg 898w, https://s.w.org/patterns/files/2021/06/wire-sculpture-768x875.jpg 768w, https://s.w.org/patterns/files/2021/06/wire-sculpture-1347x1536.jpg 1347w, https://s.w.org/patterns/files/2021/06/wire-sculpture.jpg 1658w" sizes="(max-width: 263px) 100vw, 263px" /></figure></div>\n</div></div>\n</div>\n\n\n\n<div class="wp-block-column is-vertically-aligned-center" style="padding-top:1em;padding-right:1em;padding-bottom:1em;padding-left:1em">\n<div class="wp-container-13 wp-block-columns">\n<div class="wp-block-column" style="flex-basis:320px">\n<p class="has-small-font-size" style="line-height:1.6"><strong>Airplane</strong></p>\n\n\n\n<p class="has-small-font-size" style="line-height:1.6">Copper wire, wood base. I created this piece in late 2008. For this work, I aimed to convey both the industrial heaviness of an airplane, but also the cloudlike floating quality you feel when you’re in one.</p>\n</div>\n</div>\n</div>\n</div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":7:{s:10:"spay_email";s:0:"";s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:38:"Image on solid color with description.";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:0:{}s:11:"wpop_locale";s:5:"en_US";s:20:"wpop_unlisted_reason";s:0:"";}s:14:"category_slugs";a:3:{i:0;s:8:"featured";i:1;s:6:"images";i:2;s:4:"text";}s:13:"keyword_slugs";a:0:{}s:15:"pattern_content";s:1826:"<!-- wp:columns {"align":"full"} -->\n<div class="wp-block-columns alignfull"><!-- wp:column {"width":"50%"} -->\n<div class="wp-block-column" style="flex-basis:50%"><!-- wp:cover {"customOverlayColor":"#f6f6f6","minHeight":600} -->\n<div class="wp-block-cover has-background-dim" style="background-color:#f6f6f6;min-height:600px"><div class="wp-block-cover__inner-container"><!-- wp:image {"align":"center","id":571,"sizeSlug":"medium","linkDestination":"none"} -->\n<div class="wp-block-image"><figure class="aligncenter size-medium"><img src="https://s.w.org/patterns/files/2021/06/wire-sculpture-263x300.jpg" alt="" class="wp-image-571" /></figure></div>\n<!-- /wp:image --></div></div>\n<!-- /wp:cover --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"verticalAlignment":"center","style":{"spacing":{"padding":{"top":"1em","right":"1em","bottom":"1em","left":"1em"}}}} -->\n<div class="wp-block-column is-vertically-aligned-center" style="padding-top:1em;padding-right:1em;padding-bottom:1em;padding-left:1em"><!-- wp:columns -->\n<div class="wp-block-columns"><!-- wp:column {"width":"320px"} -->\n<div class="wp-block-column" style="flex-basis:320px"><!-- wp:paragraph {"style":{"typography":{"lineHeight":"1.6"}},"fontSize":"small"} -->\n<p class="has-small-font-size" style="line-height:1.6"><strong>Airplane</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"style":{"typography":{"lineHeight":"1.6"}},"fontSize":"small"} -->\n<p class="has-small-font-size" style="line-height:1.6">Copper wire, wood base. I created this piece in late 2008. For this work, I aimed to convey both the industrial heaviness of an airplane, but also the cloudlike floating quality you feel when you’re in one.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->";}i:6;O:8:"stdClass":7:{s:2:"id";i:521;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:45:"Image with description below and to the right";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:1278:"\n<div class="wp-container-15 wp-block-columns">\n<div class="wp-block-column" style="flex-basis:10%"></div>\n\n\n\n<div class="wp-block-column">\n<figure class="wp-block-image size-large"><img loading="lazy" width="1024" height="1024" src="https://s.w.org/patterns/files/2021/06/image-from-rawpixel-id-539759-jpeg-1-1024x1024.jpg" alt="Vintage Cupid Illustration" class="wp-image-522" srcset="https://s.w.org/patterns/files/2021/06/image-from-rawpixel-id-539759-jpeg-1-1024x1024.jpg 1024w, https://s.w.org/patterns/files/2021/06/image-from-rawpixel-id-539759-jpeg-1-300x300.jpg 300w, https://s.w.org/patterns/files/2021/06/image-from-rawpixel-id-539759-jpeg-1-150x150.jpg 150w, https://s.w.org/patterns/files/2021/06/image-from-rawpixel-id-539759-jpeg-1-768x768.jpg 768w, https://s.w.org/patterns/files/2021/06/image-from-rawpixel-id-539759-jpeg-1.jpg 1510w" sizes="(max-width: 1024px) 100vw, 1024px" /></figure>\n</div>\n\n\n\n<div class="wp-block-column"></div>\n\n\n\n<div class="wp-block-column" style="flex-basis:10%"></div>\n</div>\n\n\n\n<div class="wp-container-16 wp-block-columns">\n<div class="wp-block-column"></div>\n\n\n\n<div class="wp-block-column">\n<p style="font-size:14px"><strong>Cupid in Flight</strong><br>48” x 48” Giclee print on archival paper.</p>\n</div>\n</div>\n\n\n\n<p></p>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":7:{s:10:"spay_email";s:0:"";s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:46:"Image with description below and to the right.";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:0:{}s:11:"wpop_locale";s:5:"en_US";s:20:"wpop_unlisted_reason";s:0:"";}s:14:"category_slugs";a:2:{i:0;s:8:"featured";i:1;s:6:"images";}s:13:"keyword_slugs";a:0:{}s:15:"pattern_content";s:1241:"<!-- wp:columns -->\n<div class="wp-block-columns"><!-- wp:column {"width":"10%"} -->\n<div class="wp-block-column" style="flex-basis:10%"></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"><!-- wp:image {"id":522,"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://s.w.org/patterns/files/2021/06/image-from-rawpixel-id-539759-jpeg-1-1024x1024.jpg" alt="Vintage Cupid Illustration" class="wp-i