00;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:21:"Three columns of text";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:817:"\n<div class="wp-container-28 wp-block-columns alignfull has-text-color has-background" style="background-color:#ffffff;color:#000000">\n<div class="wp-block-column">\n<h3 style="font-size:24px;line-height:1.3"><strong><a href="http://wordpress.org">Virtual Tour ↗</a></strong></h3>\n\n\n\n<p>Get a virtual tour of the museum. Ideal for schools and events.</p>\n</div>\n\n\n\n<div class="wp-block-column">\n<h3 style="font-size:24px;line-height:1.3"><strong><a href="https://wordpress.org">Current Shows ↗</a></strong></h3>\n\n\n\n<p>Stay updated and see our current exhibitions here.</p>\n</div>\n\n\n\n<div class="wp-block-column">\n<h3 style="font-size:24px;line-height:1.3"><strong><a href="https://wordpress.org">Useful Info ↗</a></strong></h3>\n\n\n\n<p>Get to know our opening times, ticket prices and discounts.</p>\n</div>\n</div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":7:{s:10:"spay_email";s:0:"";s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:22:"Three columns of text.";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:0:{}s:11:"wpop_locale";s:5:"en_US";s:20:"wpop_unlisted_reason";s:0:"";}s:14:"category_slugs";a:3:{i:0;s:7:"columns";i:1;s:8:"featured";i:2;s:4:"text";}s:13:"keyword_slugs";a:1:{i:0;s:4:"core";}s:15:"pattern_content";s:1496:"<!-- wp:columns {"align":"full","style":{"color":{"text":"#000000","background":"#ffffff"}}} -->\n<div class="wp-block-columns alignfull has-text-color has-background" style="background-color:#ffffff;color:#000000"><!-- wp:column -->\n<div class="wp-block-column"><!-- wp:heading {"level":3,"style":{"typography":{"fontSize":"24px","lineHeight":"1.3"}}} -->\n<h3 style="font-size:24px;line-height:1.3"><strong><a href="http://wordpress.org">Virtual Tour ↗</a></strong></h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Get a virtual tour of the museum. Ideal for schools and events.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"><!-- wp:heading {"level":3,"style":{"typography":{"fontSize":"24px","lineHeight":"1.3"}}} -->\n<h3 style="font-size:24px;line-height:1.3"><strong><a href="https://wordpress.org">Current Shows ↗</a></strong></h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Stay updated and see our current exhibitions here.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"><!-- wp:heading {"level":3,"style":{"typography":{"fontSize":"24px","lineHeight":"1.3"}}} -->\n<h3 style="font-size:24px;line-height:1.3"><strong><a href="https://wordpress.org">Useful Info ↗</a></strong></h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Get to know our opening times, ticket prices and discounts.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->";}i:13;O:8:"stdClass":7:{s:2:"id";i:199;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:34:"Three columns with images and text";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:2689:"\n<div class="wp-container-32 wp-block-group alignfull has-background" style="background-color:#f8f4e4"><div class="wp-block-group__inner-container">\n<div class="wp-container-29 wp-block-columns alignwide">\n<div class="wp-block-column">\n<div style="height:100px" aria-hidden="true" class="wp-block-spacer"></div>\n\n\n\n<h6 class="has-text-color" id="ecosystem" style="color:#000000">ECOSYSTEM</h6>\n\n\n\n<p class="has-text-color" style="color:#000000;font-size:5vw;line-height:1.1"><strong>Positive growth.</strong></p>\n\n\n\n<div style="height:5px" aria-hidden="true" class="wp-block-spacer"></div>\n</div>\n</div>\n\n\n\n<div class="wp-container-30 wp-block-columns alignwide">\n<div class="wp-block-column" style="flex-basis:33.38%">\n<p class="has-text-color has-extra-small-font-size" style="color:#000000"><em>Nature</em>, in the common sense, refers to essences unchanged by man; space, the air, the river, the leaf.&nbsp;<em>Art</em>&nbsp;is applied to the mixture of his will with the same things, as in a house, a canal, a statue, a picture. But his operations taken together are so insignificant, a little chipping, baking, patching, and washing, that in an impression so grand as that of the world on the human mind, they do not vary the result.</p>\n</div>\n\n\n\n<div class="wp-block-column" style="flex-basis:33%">\n<div style="height:100px" aria-hidden="true" class="wp-block-spacer"></div>\n\n\n\n<figure class="wp-block-image size-large"><img src="https://s.w.org/images/core/5.8/outside-01.jpg" alt="The sun setting through a dense forest." /></figure>\n</div>\n\n\n\n<div class="wp-block-column" style="flex-basis:33.62%">\n<figure class="wp-block-image size-large"><img src="https://s.w.org/images/core/5.8/outside-02.jpg" alt="Wind turbines standing on a grassy plain, against a blue sky." /></figure>\n</div>\n</div>\n\n\n\n<div class="wp-container-31 wp-block-columns alignwide">\n<div class="wp-block-column" style="flex-basis:67%">\n<div class="wp-block-image"><figure class="alignright size-large"><img src="https://s.w.org/images/core/5.8/outside-03.jpg" alt="The sun shining over a ridge leading down into the shore. In the distance, a car drives down a road." /></figure></div>\n</div>\n\n\n\n<div class="wp-block-column is-vertically-aligned-center" style="flex-basis:33%">\n<p class="has-text-color has-extra-small-font-size" style="color:#000000">Undoubtedly we have no questions to ask which are unanswerable. We must trust the perfection of the creation so far, as to believe that whatever curiosity the order of things has awakened in our minds, the order of things can satisfy. Every man&#8217;s condition is a solution in hieroglyphic to those inquiries he would put.</p>\n</div>\n</div>\n</div></div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":7:{s:10:"spay_email";s:0:"";s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:77:"Three columns with images and text, with vertical spacing for an offset look.";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:0:{}s:11:"wpop_locale";s:5:"en_US";s:20:"wpop_unlisted_reason";s:0:"";}s:14:"category_slugs";a:2:{i:0;s:7:"columns";i:1;s:8:"featured";}s:13:"keyword_slugs";a:1:{i:0;s:4:"core";}s:15:"pattern_content";s:3990:"<!-- wp:group {"align":"full","style":{"color":{"background":"#f8f4e4"}}} -->\n<div class="wp-block-group alignfull has-background" style="background-color:#f8f4e4"><!-- wp:columns {"align":"wide"} -->\n<div class="wp-block-columns alignwide"><!-- wp:column -->\n<div class="wp-block-column"><!-- wp:spacer -->\n<div style="height:100px" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:heading {"level":6,"style":{"color":{"text":"#000000"}}} -->\n<h6 class="has-text-color" id="ecosystem" style="color:#000000">ECOSYSTEM</h6>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"style":{"typography":{"lineHeight":"1.1","fontSize":"5vw"},"color":{"text":"#000000"}}} -->\n<p class="has-text-color" style="color:#000000;font-size:5vw;line-height:1.1"><strong>Positive growth.</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:spacer {"height":"5px"} -->\n<div style="height:5px" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns {"align":"wide"} -->\n<div class="wp-block-columns alignwide"><!-- wp:column {"width":"33.38%"} -->\n<div class="wp-block-column" style="flex-basis:33.38%"><!-- wp:paragraph {"style":{"color":{"text":"#000000"}},"fontSize":"extra-small"} -->\n<p class="has-text-color has-extra-small-font-size" style="color:#000000"><em>Nature</em>, in the common sense, refers to essences unchanged by man; space, the air, the river, the leaf.&nbsp;<em>Art</em>&nbsp;is applied to the mixture of his will with the same things, as in a house, a canal, a statue, a picture. But his operations taken together are so insignificant, a little chipping, baking, patching, and washing, that in an impression so grand as that of the world on the human mind, they do not vary the result.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"width":"33%"} -->\n<div class="wp-block-column" style="flex-basis:33%"><!-- wp:spacer -->\n<div style="height:100px" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:image {"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://s.w.org/images/core/5.8/outside-01.jpg" alt="The sun setting through a dense forest." /></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"width":"33.62%"} -->\n<div class="wp-block-column" style="flex-basis:33.62%"><!-- wp:image {"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://s.w.org/images/core/5.8/outside-02.jpg" alt="Wind turbines standing on a grassy plain, against a blue sky." /></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns {"align":"wide"} -->\n<div class="wp-block-columns alignwide"><!-- wp:column {"width":"67%"} -->\n<div class="wp-block-column" style="flex-basis:67%"><!-- wp:image {"align":"right","sizeSlug":"large","linkDestination":"none"} -->\n<div class="wp-block-image"><figure class="alignright size-large"><img src="https://s.w.org/images/core/5.8/outside-03.jpg" alt="The sun shining over a ridge leading down into the shore. In the distance, a car drives down a road." /></figure></div>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"verticalAlignment":"center","width":"33%"} -->\n<div class="wp-block-column is-vertically-aligned-center" style="flex-basis:33%"><!-- wp:paragraph {"style":{"color":{"text":"#000000"}},"fontSize":"extra-small"} -->\n<p class="has-text-color has-extra-small-font-size" style="color:#000000">Undoubtedly we have no questions to ask which are unanswerable. We must trust the perfection of the creation so far, as to believe that whatever curiosity the order of things has awakened in our minds, the order of things can satisfy. Every man''s condition is a solution in hieroglyphic to those inquiries he would put.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->";}}', 'no');
