(47145, '_site_transient_wp_remote_block_patterns_1e5d29b701869a94afea7c2', 'a:13:{i:0;O:8:"stdClass":7:{s:2:"id";i:184;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:7:"Heading";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:509:"\n<h2 class="alignwide" id="we-re-a-studio-in-berlin-with-an-international-practice-in-architecture-urban-planning-and-interior-design-we-believe-in-sharing-knowledge-and-promoting-dialogue-to-increase-the-creative-potential-of-collaboration" style="font-size:48px;line-height:1.1">We&#8217;re a studio in Berlin with an international practice in architecture, urban planning and interior design. We believe in sharing knowledge and promoting dialogue to increase the creative potential of collaboration.</h2>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":7:{s:10:"spay_email";s:0:"";s:13:"wpop_keywords";s:17:"large text, title";s:16:"wpop_description";s:12:"Heading text";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:1:{i:0;s:12:"core/heading";}s:11:"wpop_locale";s:5:"en_US";s:20:"wpop_unlisted_reason";s:0:"";}s:14:"category_slugs";a:2:{i:0;s:8:"featured";i:1;s:4:"text";}s:13:"keyword_slugs";a:1:{i:0;s:4:"core";}s:15:"pattern_content";s:621:"<!-- wp:heading {"align":"wide","style":{"typography":{"fontSize":"48px","lineHeight":"1.1"}}} -->\n<h2 class="alignwide" id="we-re-a-studio-in-berlin-with-an-international-practice-in-architecture-urban-planning-and-interior-design-we-believe-in-sharing-knowledge-and-promoting-dialogue-to-increase-the-creative-potential-of-collaboration" style="font-size:48px;line-height:1.1">We''re a studio in Berlin with an international practice in architecture, urban planning and interior design. We believe in sharing knowledge and promoting dialogue to increase the creative potential of collaboration.</h2>\n<!-- /wp:heading -->";}i:1;O:8:"stdClass":7:{s:2:"id";i:185;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:35:"Large header with left-aligned text";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:1231:"\n<div class="wp-block-cover alignfull has-background-dim-60 has-background-dim" style="min-height:800px"><img class="wp-block-cover__image-background" alt="" src="https://s.w.org/images/core/5.8/forest.jpg" data-object-fit="cover" /><div class="wp-block-cover__inner-container">\n<h2 class="alignwide has-text-color" style="color:#ffe074;font-size:64px">Forest.</h2>\n\n\n\n<div class="wp-container-623384af0717f wp-block-columns alignwide">\n<div class="wp-block-column" style="flex-basis:55%">\n<div style="height:330px" aria-hidden="true" class="wp-block-spacer"></div>\n\n\n\n<p class="has-text-color" style="color:#ffe074;font-size:12px;line-height:1.3"><em>Even a child knows how valuable the forest is. The fresh, breathtaking smell of trees. Echoing birds flying above that dense magnitude. A stable climate, a sustainable diverse life and a source of culture. Yet, forests and other ecosystems hang in the balance, threatened to become croplands, pasture, and plantations.</em></p>\n</div>\n\n\n\n<div class="wp-block-column"></div>\n</div>\n<style>.wp-container-623384af0717f {display: flex;gap: var( --wp--style--block-gap, 0.5em );flex-wrap: nowrap;align-items: center;}.wp-container-623384af0717f > * { margin: 0; }</style></div></div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":7:{s:10:"spay_email";s:0:"";s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:29:"Cover image with quote on top";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:0:{}s:11:"wpop_locale";s:5:"en_US";s:20:"wpop_unlisted_reason";s:0:"";}s:14:"category_slugs";a:2:{i:0;s:8:"featured";i:1;s:6:"header";}s:13:"keyword_slugs";a:1:{i:0;s:4:"core";}s:15:"pattern_content";s:1610:"<!-- wp:cover {"url":"https://s.w.org/images/core/5.8/forest.jpg","dimRatio":60,"minHeight":800,"align":"full"} -->\n<div class="wp-block-cover alignfull has-background-dim-60 has-background-dim" style="min-height:800px"><img class="wp-block-cover__image-background" alt="" src="https://s.w.org/images/core/5.8/forest.jpg" data-object-fit="cover" /><div class="wp-block-cover__inner-container"><!-- wp:heading {"align":"wide","style":{"color":{"text":"#ffe074"},"typography":{"fontSize":"64px"}}} -->\n<h2 class="alignwide has-text-color" style="color:#ffe074;font-size:64px">Forest.</h2>\n<!-- /wp:heading -->\n\n<!-- wp:columns {"align":"wide"} -->\n<div class="wp-block-columns alignwide"><!-- wp:column {"width":"55%"} -->\n<div class="wp-block-column" style="flex-basis:55%"><!-- wp:spacer {"height":330} -->\n<div style="height:330px" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:paragraph {"style":{"color":{"text":"#ffe074"},"typography":{"lineHeight":"1.3","fontSize":"12px"}}} -->\n<p class="has-text-color" style="color:#ffe074;font-size:12px;line-height:1.3"><em>Even a child knows how valuable the forest is. The fresh, breathtaking smell of trees. Echoing birds flying above that dense magnitude. A stable climate, a sustainable diverse life and a source of culture. Yet, forests and other ecosystems hang in the balance, threatened to become croplands, pasture, and plantations.</em></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div></div>\n<!-- /wp:cover -->";}i:2;O:8:"stdClass":7:{s:2:"id";i:186;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:35:"Large header with text and a button";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:1477:"\n<div class="wp-block-cover alignfull has-background-dim-40 has-background-dim has-parallax" style="background-image:url(https://s.w.org/images/core/5.8/art-01.jpg);background-color:#000000;min-height:100vh"><div class="wp-block-cover__inner-container">\n<h2 class="alignwide has-white-color has-text-color" style="font-size:48px;line-height:1.2"><strong><em>Overseas:</em></strong><br><strong><em>1500 — 1960</em></strong></h2>\n\n\n\n<div class="wp-container-623384af083f9 wp-block-columns alignwide">\n<div class="wp-block-column" style="flex-basis:60%">\n<p class="has-text-color" style="color:#ffffff">An exhibition about the different representations of the ocean throughout time, between the sixteenth and the twentieth century. Taking place in our Open Room in <em>Floor 2</em>.</p>\n\n\n\n<div class="wp-container-623384af080c1 wp-block-buttons">\n<div class="wp-block-button is-style-outline"><a class="wp-block-button__link has-text-color has-background no-border-radius" style="background-color:#000000;color:#ffffff">Visit</a></div>\n</div>\n<style>.wp-container-623384af080c1 {display: flex;gap: var( --wp--style--block-gap, 0.5em );flex-wrap: wrap;align-items: center;}.wp-container-623384af080c1 > * { margin: 0; }</style></div>\n\n\n\n<div class="wp-block-column"></div>\n</div>\n<style>.wp-container-623384af083f9 {display: flex;gap: var( --wp--style--block-gap, 0.5em );flex-wrap: nowrap;align-items: center;}.wp-container-623384af083f9 > * { margin: 0; }</style></div></div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":7:{s:10:"spay_email";s:0:"";s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:62:"Large header with background image and text and button on top.";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:0:{}s:11:"wpop_locale";s:5:"en_US";s:20:"wpop_unlisted_reason";s:0:"";}s:14:"category_slugs";a:1:{i:0;s:6:"header";}s:13:"keyword_slugs";a:1:{i:0;s:4:"core";}s:15:"pattern_content";s:1865:"<!-- wp:cover {"url":"https://s.w.org/images/core/5.8/art-01.jpg","hasParallax":true,"dimRatio":40,"customOverlayColor":"#000000","minHeight":100,"minHeightUnit":"vh","contentPosition":"center center","align":"full"} -->\n<div class="wp-block-cover alignfull has-background-dim-40 has-background-dim has-parallax" style="background-image:url(https://s.w.org/images/core/5.8/art-01.jpg);background-color:#000000;min-height:100vh"><div class="wp-block-cover__inner-container"><!-- wp:heading {"style":{"typography":{"fontSize":"48px","lineHeight":"1.2"}},"className":"alignwide has-white-color has-text-color"} -->\n<h2 class="alignwide has-white-color has-text-color" style="font-size:48px;line-height:1.2"><strong><em>Overseas:</em></strong><br><strong><em>1500 — 1960</em></strong></h2>\n<!-- /wp:heading -->\n\n<!-- wp:columns {"align":"wide"} -->\n<div class="wp-block-columns alignwide"><!-- wp:column {"width":"60%"} -->\n<div class="wp-block-column" style="flex-basis:60%"><!-- wp:paragraph {"style":{"color":{"text":"#ffffff"}}} -->\n<p class="has-text-color" style="color:#ffffff">An exhibition about the different representations of the ocean throughout time, between the sixteenth and the twentieth century. Taking place in our Open Room in <em>Floor 2</em>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class="wp-block-buttons"><!-- wp:button {"borderRadius":0,"style":{"color":{"text":"#ffffff","background":"#000000"}},"className":"is-style-outline"} -->\n<div class="wp-block-button is-style-outline"><a class="wp-block-button__link has-text-color has-background no-border-radius" style="background-color:#000000;color:#ffffff">Visit</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div></div>\n<!-- /wp:cover -->";}i:3;O:8:"stdClass":7:{s:2:"id";i:196;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:41:"Media and text in a full height container";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:1404:"\n<div class="wp-block-cover alignfull has-background-dim" style="background-color:#ffffff;min-height:100vh"><div class="wp-block-cover__inner-container">\n<div class="wp-block-media-text alignwide is-stacked-on-mobile is-vertically-aligned-center is-image-fill" style="grid-template-columns:56% auto"><figure class="wp-block-media-text__media" style="background-image:url(https://s.w.org/images/core/5.8/soil.jpg);background-position:50% 50%"><img src="https://s.w.org/images/core/5.8/soil.jpg" alt="Close-up of dried, cracked earth." /></figure><div class="wp-block-media-text__content">\n<h2 class="has-text-color" style="color:#000000;font-size:32px"><strong>What&#8217;s the problem?</strong></h2>\n\n\n\n<p class="has-text-color" style="color:#000000;font-size:17px">Trees are more important today than ever before. More than 10,000 products are reportedly made from trees. Through chemistry, the humble woodpile is yielding chemicals, plastics and fabrics that were beyond comprehension when an axe first felled a Texas tree.</p>\n\n\n\n<div class="wp-container-623384af09355 wp-block-buttons">\n<div class="wp-block-button is-style-fill"><a class="wp-block-button__link">Learn more</a></div>\n</div>\n<style>.wp-container-623384af09355 {display: flex;gap: var( --wp--style--block-gap, 0.5em );flex-wrap: wrap;align-items: center;}.wp-container-623384af09355 > * { margin: 0; }</style></div></div>\n</div></div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":7:{s:10:"spay_email";s:0:"";s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:77:"Media and text block with image to the left and text and button to the right.";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:0:{}s:11:"wpop_locale";s:5:"en_US";s:20:"wpop_unlisted_reason";s:0:"";}s:14:"category_slugs";a:1:{i:0;s:6:"header";}s:13:"keyword_slugs";a:1:{i:0;s:4:"core";}s:15:"pattern_content";s:1858:"<!-- wp:cover {"customOverlayColor":"#ffffff","minHeight":100,"minHeightUnit":"vh","contentPosition":"center center","align":"full"} -->\n<div class="wp-block-cover alignfull has-background-dim" style="background-color:#ffffff;min-height:100vh"><div class="wp-block-cover__inner-container"><!-- wp:media-text {"mediaLink":"https://s.w.org/images/core/5.8/soil.jpg","mediaType":"image","mediaWidth":56,"verticalAlignment":"center","imageFill":true} -->\n<div class="wp-block-media-text alignwide is-stacked-on-mobile is-vertically-aligned-center is-image-fill" style="grid-template-columns:56% auto"><figure class="wp-block-media-text__media" style="background-image:url(https://s.w.org/images/core/5.8/soil.jpg);background-position:50% 50%"><img src="https://s.w.org/images/core/5.8/soil.jpg" alt="Close-up of dried, cracked earth." /></figure><div class="wp-block-media-text__content"><!-- wp:heading {"style":{"typography":{"fontSize":"32px"},"color":{"text":"#000000"}}} -->\n<h2 class="has-text-color" style="color:#000000;font-size:32px"><strong>What''s the problem?</strong></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"style":{"typography":{"fontSize":"17px"},"color":{"text":"#000000"}}} -->\n<p class="has-text-color" style="color:#000000;font-size:17px">Trees are more important today than ever before. More than 10,000 products are reportedly made from trees. Through chemistry, the humble woodpile is yielding chemicals, plastics and fabrics that were beyond comprehension when an axe first felled a Texas tree.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class="wp-block-buttons"><!-- wp:button {"className":"is-style-fill"} -->\n<div class="wp-block-button is-style-fill"><a class="wp-block-button__link">Learn more</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div></div>\n<!-- /wp:media-text --></div></div>\n<!-- /wp:cover -->";}i:4;O:8:"stdClass":7:{s:2:"id";i:192;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:37:"Media and text with image on the left";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:520:"\n<div class="wp-block-media-text alignfull is-stacked-on-mobile is-vertically-aligned-center"><figure class="wp-block-media-text__media"><img src="https://s.w.org/images/core/5.8/architecture-04.jpg" alt="Close-up, abstract view of architecture." /></figure><div class="wp-block-media-text__content">\n<h3 class="has-text-align-center has-text-color" style="color:#000000"><strong>Open Spaces</strong></h3>\n\n\n\n<p class="has-text-align-center has-extra-small-font-size"><a href="#">See case study ↗</a></p>\n</div></div>\n";s