(1155, 122, 'extra', '<br><a href="http://www.peterlucker-arts.com/572"><strong>Vergroting schilderij  Ketchikan Creek Street  Alaska  zien       (klik hier)  </strong></a>'),
(1160, 122, 'extra', 'Toelichting:\r\nOorspronkelijk een plek voor zalmverwerking.\r\n(1883 salmon saltery,  1885 salmon cannery)\r\nDe houten huizen op palen dienden vroeger als smokkelroutes voor sterke drank, \r\nvoor de talloze goudzoekers.\r\nVia luiken in de bodem van de huizen kon men met bootjes bij hoog water s''avonds toch voorzien worden van drank  in de toen barre omstandigheden.\r\nBovendien voorzagen deze huizen in de behoefte naar prostitutie.\r\nTegenwoordig doen de huizen dienst als souvenirswinkels en als toeristische attractie.\r\nDe wonderlijke kleuren van de weerspiegeling in het water van de houten huizen spraken mij zeer aan.\r\nEvenals de wirwar van scheve planken en bouwsels in het water.\r\n'),
(1167, 580, '_wp_attached_file', '2011/04/Ketchikan-Creekstreet-Alaska.jpg'),
(1168, 580, '_wp_attachment_metadata', 'a:6:{s:5:"width";s:4:"1018";s:6:"height";s:3:"767";s:14:"hwstring_small";s:23:"height=''96'' width=''128''";s:4:"file";s:40:"2011/04/Ketchikan-Creekstreet-Alaska.jpg";s:5:"sizes";a:2:{s:9:"thumbnail";a:3:{s:4:"file";s:40:"Ketchikan-Creekstreet-Alaska-150x150.jpg";s:5:"width";s:3:"150";s:6:"height";s:3:"150";}s:6:"medium";a:3:{s:4:"file";s:40:"Ketchikan-Creekstreet-Alaska-300x226.jpg";s:5:"width";s:3:"300";s:6:"height";s:3:"226";}}s:10:"image_meta";a:10:{s:8:"aperture";s:1:"0";s:6:"credit";s:0:"";s:6:"camera";s:0:"";s:7:"caption";s:0:"";s:17:"created_timestamp";s:1:"0";s:9:"copyright";s:0:"";s:12:"focal_length";s:1:"0";s:3:"iso";s:1:"0";s:13:"shutter_speed";s:1:"0";s:5:"title";s:0:"";}}'),
