(1170, 581, '_wp_attachment_metadata', 'a:6:{s:5:"width";s:3:"900";s:6:"height";s:3:"656";s:14:"hwstring_small";s:23:"height=''93'' width=''128''";s:4:"file";s:31:"2011/04/Porec-aanlegsteiger.jpg";s:5:"sizes";a:2:{s:9:"thumbnail";a:3:{s:4:"file";s:31:"Porec-aanlegsteiger-150x150.jpg";s:5:"width";s:3:"150";s:6:"height";s:3:"150";}s:6:"medium";a:3:{s:4:"file";s:31:"Porec-aanlegsteiger-300x218.jpg";s:5:"width";s:3:"300";s:6:"height";s:3:"218";}}s:10:"image_meta";a:10:{s:8:"aperture";s:1:"0";s:6:"credit";s:0:"";s:6:"camera";s:0:"";s:7:"caption";s:0:"";s:17:"created_timestamp";s:1:"0";s:9:"copyright";s:0:"";s:12:"focal_length";s:1:"0";s:3:"iso";s:1:"0";s:13:"shutter_speed";s:1:"0";s:5:"title";s:0:"";}}'),
(1177, 181, 'extra', 'Toelichting:                                  \r\nHet historische van de oude kern van Porec wordt langzaam aangetast door de tijd.\r\nVoorgrond de twee oude boten liggend aan de middeleeuwse kern van de stad aan een zeer gammele steiger.\r\nDaarachter enkele nieuwe boten met motoren en in de verte een bonte gekleurde luidruchtige kermis die vooral\r\n''s avonds het rustieke van het oude gedeelte van de stad aantast.\r\nVooral de diverse stromingen in het water van de zee en de baai en de stilte onder de steiger spraken mij aan.'),
