(1270, 634, '_wp_attachment_metadata', 'a:6:{s:5:"width";s:3:"500";s:6:"height";s:3:"253";s:14:"hwstring_small";s:23:"height=''64'' width=''128''";s:4:"file";s:28:"2011/07/De-volgende-stap.jpg";s:5:"sizes";a:2:{s:9:"thumbnail";a:3:{s:4:"file";s:28:"De-volgende-stap-150x150.jpg";s:5:"width";s:3:"150";s:6:"height";s:3:"150";}s:6:"medium";a:3:{s:4:"file";s:28:"De-volgende-stap-300x151.jpg";s:5:"width";s:3:"300";s:6:"height";s:3:"151";}}s:10:"image_meta";a:10:{s:8:"aperture";s:1:"0";s:6:"credit";s:0:"";s:6:"camera";s:0:"";s:7:"caption";s:0:"";s:17:"created_timestamp";s:1:"0";s:9:"copyright";s:0:"";s:12:"focal_length";s:1:"0";s:3:"iso";s:1:"0";s:13:"shutter_speed";s:1:"0";s:5:"title";s:0:"";}}'),
(1271, 633, 'jaar', '2011'),
(1274, 589, 'extra', '<br><a href="http://www.peterlucker-arts.com/633"><strong>KLIK  voor stap 3  </strong></a>'),
(1277, 319, 'extra', 'Versmelting in beeld, gebaar en handeling. \r\nOplossen in de voorstelling.'),
(1286, 53, 'extra', 'Een onzichtbare driehoek vormt de schakel tussen lucht en water en vormt de basis voor elkaars spiegel en omgeving.\r\nZie wat er niet is en ontdek de spiegeling.'),
(1297, 51, 'extra', 'De doorzichtige glazen driehoek die zich losmaakt van de achtergrond, zich optilt en verwijdert van de andere grote driehoeken.'),
(1304, 38, 'extra', 'Een liggende blauwe vrouw, zie hoofd, borsten arm en heup, vormt het landschap dat opgebouwd is uit enkel vrouwelijke vormen, evenals de lucht en de voorgrond. De lijnen gaan verder op de zijvlakken.'),
(1311, 452, 'extra', 'Wens en werkelijkheid, wat men wil geloven en in werkelijkheid de ogen voor sluit, uitgedrukt in het groen van de lucht en het rode (bloed) van de rivier, wat men zegt en wat men doet.\r\nHet werkelijke aangezicht van de aarde en de mensen die er wonen bedreigd door een sluipende wolk van de andere kant.\r\nWanneer zal het zwakke oplichtende (landschap : zie liggend gezicht)  beetje hoop nog ontwaken?'),
(1316, 58, 'extra', 'De maten 2 8 4 vormen de steeds links en rechts wederkerende vaste waarden waartussen de snijdende lijnen driehoeken vormen waarvan de punten liggen midden in de bovenstaande figuur binnen het volgende vierkant.\r\nEen onzichtbare verbinding vormt een evenwicht tussen de veranderende figuren in een wisselende volgorde die een steeds andere diepte suggereert.'),
(1321, 438, 'extra', 'Een landschap waar kleuren en vormen zijn gedeformeerd tot eenkleurige driehoeken.\r\nLijnen die verwijzen naar een nietig punt in een overweldigende omgeving van grote imposante massa''s.\r\n(zie het rode dak als nietig punt)\r\nHet oog blijft dwalen en zoeken terwijl steeds grotere driehoeken zich verheffen omsluiten en bedreigen.\r\nDe lichte niveau''s  bieden ontsnapping. Lijnen aan alle zijkanten lopen door (3D).'),
