(1927, 941, 'extra', 'FEMALE WAVE    \r\nHerhalende witte, door de hemelsblauwe lucht verlichte, oprijzende schuimwolken uit de donkere turquoise blauwe oceaan, als zachte flexibele vrouwelijke vormen die opeens oprijzen en weer verdwijnen in de kleuren van de ondergaande zon.                                                                                                                              \r\n'),
(1956, 975, '_wp_attached_file', '2013/04/Legato-500.jpg'),
(1954, 974, '_edit_last', '1'),
(1955, 974, '_edit_lock', '1391003942:1'),
(1928, 941, 'extra', 'Door de strakke sterke kleurcontrasten en de verdwijnende zwarte contourlijnen ontstaan losse ruimtelijke vlakken zoals een decorstuk, waarachter zich weer het volgende decorstuk bevindt, alsof je je hand ertussen zou kunnen steken. Het zonlicht weerkaatsend op het water, versterkt die indruk van diepte.'),
(1957, 975, '_wp_attachment_metadata', 'a:5:{s:5:"width";i:500;s:6:"height";i:283;s:4:"file";s:22:"2013/04/Legato-500.jpg";s:5:"sizes";a:2:{s:9:"thumbnail";a:4:{s:4:"file";s:22:"Legato-500-150x150.jpg";s:5:"width";i:150;s:6:"height";i:150;s:9:"mime-type";s:10:"image/jpeg";}s:6:"medium";a:4:{s:4:"file";s:22:"Legato-500-300x169.jpg";s:5:"width";i:300;s:6:"height";i:169;s:9:"mime-type";s:10:"image/jpeg";}}s:10:"image_meta";a:10:{s:8:"aperture";i:0;s:6:"credit";s:0:"";s:6:"camera";s:0:"";s:7:"caption";s:0:"";s:17:"created_timestamp";i:0;s:9:"copyright";s:0:"";s:12:"focal_length";i:0;s:3:"iso";i:0;s:13:"shutter_speed";i:0;s:5:"title";s:0:"";}}'),
