(51, 1, '2010-10-15 16:41:52', '2010-10-15 16:41:52', '[caption id="attachment_233" align="alignnone" width="500" caption="De glazen driehoek maakt zich los"]<img class="size-full wp-image-233" title="A1 De Driehoek 1 320" src="http://www.peterlucker-arts.com/wp-content/uploads/2010/10/A1-De-Driehoek-1-320-e1288125591172.jpg" alt="" width="500" height="375" />[/caption]', ' De driehoek І', '', 'publish', 'open', 'open', '', 'abstract-3', '', '', '2011-07-05 13:30:29', '2011-07-05 13:30:29', '', 0, 'http://www.buurnet.nl/pla/?p=51', 0, 'post', '', 0),
